import{_ as n,c as i,o as t,a1 as s}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Kontext-Komprimierung: Automatische Skill-Wiederherstellung | opencode-agent-skills","description":"Lernen Sie den Kontext-Komprimierungs-Wiederherstellungsmechanismus von opencode-agent-skills kennen. Automatische Wiederherstellung der Skill-Liste nach einer Sitzungskomprimierung unter Verwendung von Synthetic-Nachrichten zur Erhaltung der Skill-Verfügbarkeit.","frontmatter":{"title":"Kontext-Komprimierung: Automatische Skill-Wiederherstellung | opencode-agent-skills","sidebarTitle":"Skills bleiben nach Komprimierung erhalten","subtitle":"Kontext-Komprimierung: Automatische Skill-Wiederherstellung","description":"Lernen Sie den Kontext-Komprimierungs-Wiederherstellungsmechanismus von opencode-agent-skills kennen. Automatische Wiederherstellung der Skill-Liste nach einer Sitzungskomprimierung unter Verwendung von Synthetic-Nachrichten zur Erhaltung der Skill-Verfügbarkeit.","tags":["Kontextverwaltung","Sitzungspersistenz","Erweiterte Funktionen"],"prerequisite":["platforms-loading-skills-into-context"],"order":4},"headers":[],"relativePath":"de/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md","filePath":"de/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"}'),r={name:"de/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"};function l(a,e,o,d,h,u){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="kontext-komprimierungs-wiederherstellungsmechanismus" tabindex="-1">Kontext-Komprimierungs-Wiederherstellungsmechanismus <a class="header-anchor" href="#kontext-komprimierungs-wiederherstellungsmechanismus" aria-label="Permalink to &quot;Kontext-Komprimierungs-Wiederherstellungsmechanismus&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen-werden" tabindex="-1">Was Sie nach diesem Tutorial können werden <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen-werden" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können werden&quot;">​</a></h2><ul><li>Verstehen, wie Plugins Skills nach einer Sitzungskomprimierung verfügbar halten</li><li>Die Auslösebedingungen und den Ausführungsablauf der Wiederherstellung kennen</li><li>Verifizieren können, ob die Komprimierungswiederherstellung ordnungsgemäß funktioniert</li><li>Die Rolle von Synthetic-Nachrichten im Wiederherstellungsmechanismus verstehen</li></ul><h2 id="ihre-aktuelle-herausforderung" tabindex="-1">Ihre aktuelle Herausforderung <a class="header-anchor" href="#ihre-aktuelle-herausforderung" aria-label="Permalink to &quot;Ihre aktuelle Herausforderung&quot;">​</a></h2><p>In langen Sitzungen führt OpenCode eine <strong>Kontextkomprimierung</strong> (Context Compaction) durch, um Token zu sparen. Nach der Komprimierung behält die Sitzung nur die neuesten Nachrichten bei, frühere Verlaufseinträge (einschließlich zuvor injizierter Skill-Inhalte) werden entfernt.</p><p>Dies führt zu einem Problem: Wenn der Skill-Inhalt komprimiert und entfernt wurde, weiß die KI nicht mehr, welche Skills verfügbar sind, und kann keine geladenen Skills verwenden.</p><h2 id="wann-sollten-sie-diese-technik-verwenden" tabindex="-1">Wann sollten Sie diese Technik verwenden <a class="header-anchor" href="#wann-sollten-sie-diese-technik-verwenden" aria-label="Permalink to &quot;Wann sollten Sie diese Technik verwenden&quot;">​</a></h2><p>Der Komprimierungswiederherstellungsmechanismus läuft <strong>automatisch</strong> ab, Sie müssen nicht manuell eingreifen. Nach dem Verständnis der Funktionsweise können Sie in folgenden Szenarien Probleme beheben:</p><ul><li>Die KI &quot;vergisst&quot; plötzlich die Skills während einer langen Sitzung</li><li>Sie müssen die Verfügbarkeit von Skills nach der Komprimierung debuggen</li><li>Sie möchten die Sitzungsverwaltungsstrategie des Plugins verstehen</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><h3 id="was-ist-kontextkomprimierung" tabindex="-1">Was ist Kontextkomprimierung? <a class="header-anchor" href="#was-ist-kontextkomprimierung" aria-label="Permalink to &quot;Was ist Kontextkomprimierung?&quot;">​</a></h3><p>Mit zunehmender Anzahl von Nachrichten wird die OpenCode-Sitzung immer länger. Wenn die Token-Nutzung nahe an das Limit heranreicht, führt das System automatisch eine <strong>Kontextkomprimierung</strong> durch:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Sitzungsbeginn] → [Nachricht 1] → [Nachricht 2] → ... → [Nachricht 50]</span></span>
<span class="line"><span>                                  ↑ Komprimierungspunkt: Nur die letzten 10 Nachrichten behalten</span></span></code></pre></div><p>Nach der Komprimierung werden frühere Nachrichten (einschließlich Skill-Injektionsinhalte) entfernt, die KI kann nur noch die neuesten Nachrichten sehen.</p><h3 id="funktionsweise-des-komprimierungswiederherstellungsmechanismus" tabindex="-1">Funktionsweise des Komprimierungswiederherstellungsmechanismus <a class="header-anchor" href="#funktionsweise-des-komprimierungswiederherstellungsmechanismus" aria-label="Permalink to &quot;Funktionsweise des Komprimierungswiederherstellungsmechanismus&quot;">​</a></h3><p>Das Plugin überwacht das <code>session.compacted</code>-Ereignis. Sobald eine Komprimierung erkannt wird, werden sofort folgende Wiederherstellungsoperationen ausgeführt:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Sitzungskomprimierung ausgelöst] --&gt; B[session.compacted-Ereignis]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C{Superpowers aktiviert?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Ja| D[Superpowers-Eingabeaufforderung erneut injizieren]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Nein| E[Superpowers überspringen]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[Skill-Liste erneut injizieren]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[Geladene Skill-Datensätze löschen]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Wiederherstellung abgeschlossen]</span></span></code></pre></div><p><strong>Schlüsselpunkte</strong>:</p><ul><li>Die Wiederherstellung ist <strong>automatisch</strong>, keine manuelle Auslösung erforderlich</li><li>Die wiederhergestellte Skill-Liste enthält <strong>alle entdeckten Skills</strong> (nicht nur zuvor geladene)</li><li>Die Datensätze geladener Skills werden geleert, damit die KI neu bewerten kann, welche Skills benötigt werden</li></ul><h3 id="rolle-von-synthetic-nachrichten" tabindex="-1">Rolle von Synthetic-Nachrichten <a class="header-anchor" href="#rolle-von-synthetic-nachrichten" aria-label="Permalink to &quot;Rolle von Synthetic-Nachrichten&quot;">​</a></h3><p>Das Plugin verwendet den <strong>Synthetic Message Injection</strong>-Mechanismus zum Injizieren von Inhalten:</p><table tabindex="0"><thead><tr><th>Eigenschaft</th><th>Wert</th><th>Bedeutung</th></tr></thead><tbody><tr><td><code>noReply</code></td><td><code>true</code></td><td>Die KI antwortet nicht auf den Injektionsinhalt selbst</td></tr><tr><td><code>synthetic</code></td><td><code>true</code></td><td>Markiert als systemgenerierte Inhalte, werden nicht in Benutzereingaben gezählt, nicht in der UI angezeigt</td></tr></tbody></table><p>Dies bedeutet, dass die durch Komprimierungswiederherstellung injizierten Inhalte:</p><ul><li>Für den Benutzer vollständig transparent sind (nicht sichtbar)</li><li>Keine Benutzernachrichten-Kontingente verbrauchen</li><li>Aber von der KI gelesen und verstanden werden</li></ul><h2 id="🎒-vorbereitung" tabindex="-1">🎒 Vorbereitung <a class="header-anchor" href="#🎒-vorbereitung" aria-label="Permalink to &quot;🎒 Vorbereitung&quot;">​</a></h2><p>Dieses Tutorial benötigt:</p><ul><li>Das OpenCode Agent Skills Plugin ist installiert</li><li>Grundlegendes Verständnis von Skill-Laden</li><li>Eine lange Sitzung zum Testen des Komprimierungseffekts</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Keine zusätzliche Vorbereitung erforderlich, die Komprimierungswiederherstellung ist eine integrierte Plugin-Funktion.</p></div><h2 id="anleitung-uberprufung-der-komprimierungswiederherstellung" tabindex="-1">Anleitung: Überprüfung der Komprimierungswiederherstellung <a class="header-anchor" href="#anleitung-uberprufung-der-komprimierungswiederherstellung" aria-label="Permalink to &quot;Anleitung: Überprüfung der Komprimierungswiederherstellung&quot;">​</a></h2><h3 id="schritt-1-neue-sitzung-starten" tabindex="-1">Schritt 1: Neue Sitzung starten <a class="header-anchor" href="#schritt-1-neue-sitzung-starten" aria-label="Permalink to &quot;Schritt 1: Neue Sitzung starten&quot;">​</a></h3><p><strong>Warum</strong> Überprüfung, ob die Skill-Liste beim Sitzungsstart normal injiziert wird</p><p>Starten Sie eine neue Sitzung und geben Sie eine beliebige Nachricht ein:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hallo</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Die KI antwortet normal und injiziert automatisch die Skill-Liste im Hintergrund (für den Benutzer unsichtbar)</p><h3 id="schritt-2-einen-skill-laden" tabindex="-1">Schritt 2: Einen Skill laden <a class="header-anchor" href="#schritt-2-einen-skill-laden" aria-label="Permalink to &quot;Schritt 2: Einen Skill laden&quot;">​</a></h3><p><strong>Warum</strong> Sicherstellen, dass der Skill-Inhalt in den Kontext injiziert wird</p><p>Rufen Sie das <code>use_skill</code>-Tool auf:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Verwenden Sie get_available_skills, um verfügbare Skills anzuzeigen, und laden Sie dann mit use_skill einen der Skills</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Die KI listet verfügbare Skills auf und lädt dann den von Ihnen gewählten Skill</p><h3 id="schritt-3-kontextkomprimierung-auslosen" tabindex="-1">Schritt 3: Kontextkomprimierung auslösen <a class="header-anchor" href="#schritt-3-kontextkomprimierung-auslosen" aria-label="Permalink to &quot;Schritt 3: Kontextkomprimierung auslösen&quot;">​</a></h3><p><strong>Warum</strong> Simulation eines langen Sitzungsszenarios, um den OpenCode-Komprimierungsmechanismus auszulösen</p><p>Senden Sie kontinuierlich Nachrichten, um einen langen Dialog zu simulieren:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nachricht 1: Testinhalt</span></span>
<span class="line"><span>Nachricht 2: Test fortsetzen</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>（20-30 Nachrichten wiederholen）</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Mit zunehmender Anzahl von Nachrichten wird der Sitzungsverlauf länger</li><li>Wenn eine bestimmte Länge erreicht ist, führt OpenCode automatisch eine Komprimierung durch</li><li>Nach der Komprimierung werden frühe Nachrichten (einschließlich Skill-Injektion) entfernt</li></ul><h3 id="schritt-4-wiederherstellungseffekt-uberprufen" tabindex="-1">Schritt 4: Wiederherstellungseffekt überprüfen <a class="header-anchor" href="#schritt-4-wiederherstellungseffekt-uberprufen" aria-label="Permalink to &quot;Schritt 4: Wiederherstellungseffekt überprüfen&quot;">​</a></h3><p><strong>Warum</strong> Überprüfung, ob die Skill-Liste nach der Komprimierung erneut injiziert wurde</p><p>Nach der Komprimierung lassen Sie die KI den Skill erneut verwenden:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hilf mir, die git-helper-Skill zu verwenden, um einen neuen Branch zu erstellen（Angenommen, Sie haben den git-helper-Skill installiert）</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Die KI weiß immer noch, welche Skills verfügbar sind（Beweis, dass die Skill-Liste wiederhergestellt wurde）</li><li>Die KI kann Skills normal laden und verwenden（Beweis, dass die Skill-Funktion von der Komprimierung nicht beeinflusst wurde）</li></ul><h3 id="schritt-5-synthetic-message-injektion-uberprufen" tabindex="-1">Schritt 5: Synthetic-Message-Injektion überprüfen <a class="header-anchor" href="#schritt-5-synthetic-message-injektion-uberprufen" aria-label="Permalink to &quot;Schritt 5: Synthetic-Message-Injektion überprüfen&quot;">​</a></h3><p><strong>Warum</strong> Bestätigung, dass der Wiederherstellungsmechanismus Synthetic-Nachrichten verwendet, ohne den Dialog zu stören</p><p>Wenn das Plugin dies unterstützt, können Sie den Sitzungsnachrichtenverlauf überprüfen（Abhängig von der OpenCode-Funktion）:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Verwenden Sie das Debugging-Tool, um den Sitzungsnachrichtenverlauf anzuzeigen</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Wiederhergestellte Skill-Listen-Nachrichten sind als <code>synthetic: true</code> markiert</li><li>Diese Nachrichten werden nicht in der normalen Dialogoberfläche angezeigt</li></ul><h2 id="checkpoints-✅" tabindex="-1">Checkpoints ✅ <a class="header-anchor" href="#checkpoints-✅" aria-label="Permalink to &quot;Checkpoints ✅&quot;">​</a></h2><p>Nach Abschluss der oben genannten Schritte sollten Sie Folgendes bestätigen können:</p><ul><li>[ ] Die KI kann in langen Sitzungen weiterhin auf die Skill-Liste zugreifen</li><li>[ ] Die Skill-Ladefunktion funktioniert nach der Komprimierung normal</li><li>[ ] Der Wiederherstellungsprozess ist für den Benutzer vollständig transparent</li></ul><h2 id="haufige-fehlerquellen" tabindex="-1">Häufige Fehlerquellen <a class="header-anchor" href="#haufige-fehlerquellen" aria-label="Permalink to &quot;Häufige Fehlerquellen&quot;">​</a></h2><h3 id="problem-1-ki-sagt-nach-komprimierung-skill-nicht-gefunden" tabindex="-1">Problem 1: KI sagt nach Komprimierung &quot;Skill nicht gefunden&quot; <a class="header-anchor" href="#problem-1-ki-sagt-nach-komprimierung-skill-nicht-gefunden" aria-label="Permalink to &quot;Problem 1: KI sagt nach Komprimierung &quot;Skill nicht gefunden&quot;&quot;">​</a></h3><p><strong>Mögliche Ursachen</strong>:</p><ul><li>Das Plugin hat das <code>session.compacted</code>-Ereignis nicht korrekt überwacht</li><li>Der Skill-Verzeichnispfad hat sich geändert</li></ul><p><strong>Lösung</strong>:</p><ol><li><p><strong>Überprüfen, ob das Komprimierungsereignis ausgelöst wird</strong></p><ul><li>Folgen Sie Schritt 3 und 4 in der Anleitung &quot;Folge mir&quot;, um zu bestätigen, dass die KI nach der Komprimierung weiterhin auf die Skill-Liste zugreifen kann</li><li>Wenn die KI Skills normal verwenden kann, funktioniert der Komprimierungswiederherstellungsmechanismus korrekt</li></ul></li><li><p><strong>Überprüfen, ob das Plugin korrekt geladen ist</strong></p><ul><li>Starten Sie OpenCode neu</li><li>Starten Sie nach dem Start einer neuen Sitzung die KI, um verfügbare Skills aufzulisten（<code>get_available_skills</code>）</li><li>Wenn die Skill-Liste angezeigt wird, ist das Plugin korrekt geladen</li></ul></li></ol><h3 id="problem-2-wiederhergestellte-skill-liste-ist-leer" tabindex="-1">Problem 2: Wiederhergestellte Skill-Liste ist leer <a class="header-anchor" href="#problem-2-wiederhergestellte-skill-liste-ist-leer" aria-label="Permalink to &quot;Problem 2: Wiederhergestellte Skill-Liste ist leer&quot;">​</a></h3><p><strong>Mögliche Ursachen</strong>:</p><ul><li>Im Skill-Erkennungspfad sind keine Skills vorhanden</li><li>Das Skill-Dateiformat ist fehlerhaft</li></ul><p><strong>Lösung</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Manuelles Abfragen verfügbarer Skills</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Verwenden</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Sie</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get_available_skills,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> um</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> die</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Skill-Liste</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anzuzeigen</span></span></code></pre></div><p>Wenn eine leere Liste zurückgegeben wird, überprüfen Sie das Skill-Verzeichnis und das Dateiformat.</p><h3 id="problem-3-nach-komprimierung-gehen-geladene-skill-zustande-verloren" tabindex="-1">Problem 3: Nach Komprimierung gehen geladene Skill-Zustände verloren <a class="header-anchor" href="#problem-3-nach-komprimierung-gehen-geladene-skill-zustande-verloren" aria-label="Permalink to &quot;Problem 3: Nach Komprimierung gehen geladene Skill-Zustände verloren&quot;">​</a></h3><p><strong>Dies ist das erwartete Verhalten</strong>, kein Bug. Der Wiederherstellungsmechanismus leert den <code>loadedSkillsPerSession</code>-Datensatz, damit die KI neu bewerten kann, welche Skills benötigt werden.</p><p><strong>Lösung</strong>: Die KI entscheidet automatisch, ob Skills basierend auf dem Kontext neu geladen werden müssen, ohne manuellen Eingriff.</p><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><p>Der Komprimierungswiederherstellungsmechanismus stellt die Verfügbarkeit von Skills in langen Sitzungen durch folgende Maßnahmen sicher:</p><ol><li><strong>Überwachung von Komprimierungsereignissen</strong>: Automatische Erkennung des <code>session.compacted</code>-Ereignisses</li><li><strong>Erneute Injektion der Skill-Liste</strong>: Verwendung des <code>&lt;available-skills&gt;</code>-Tags zur Injektion aller Skills</li><li><strong>Optionale Superpowers-Wiederherstellung</strong>: Wenn aktiviert, gleichzeitige Wiederherstellung der Superpowers-Eingabeaufforderung</li><li><strong>Verwendung von Synthetic-Nachrichten</strong>: Der Wiederherstellungsprozess ist für den Benutzer transparent und beeinträchtigt die Konversation nicht</li><li><strong>Zurücksetzen geladener Datensätze</strong>: Leeren der geladenen Skill-Sammlung, ermöglicht eine Neubewertung</li></ol><p>Dieser Mechanismus stellt sicher:</p><ul><li>Skills sind in langen Sitzungen jederzeit verfügbar</li><li>Der Wiederherstellungsprozess ist automatisiert und nicht wahrnehmbar</li><li>Die KI kann basierend auf dem aktuellen Kontext entscheiden, welche Skills verwendet werden sollen</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../../faq/troubleshooting/">Häufige Probleme und Fehlerbehebung</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Behandlungsmethoden für häufige Fehler und Ausnahmen</li><li>Fehlerbehebungstechniken im Zusammenhang mit Komprimierungswiederherstellung</li><li>Lösungen für andere Anwendungsprobleme</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie, um die Quellcode-Position anzuzeigen</strong></summary><blockquote><p>Aktualisiert: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Komprimierungsereignis-Überwachung</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L157" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-157</td></tr><tr><td>Erste Nachrichten-Initialisierung</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L70-L105" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>70-105</td></tr><tr><td>Skill-Listen-Injektion</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L345-L370" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>345-370</td></tr><tr><td>Synthetic-Nachrichten-Injektion</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Sitzungszustandsverwaltung</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L25-L35" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>25-35</td></tr></tbody></table><p><strong>Wichtige Variablen</strong>:</p><ul><li><code>setupCompleteSessions: Set&lt;string&gt;</code>: Speichert die ID von Sitzungen, die die Initialisierung abgeschlossen haben</li><li><code>loadedSkillsPerSession: Map&lt;string, Set&lt;string&gt;&gt;</code>: Speichert die Namen von Skills, die in jeder Sitzung geladen wurden</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>injectSkillsList()</code>: Injiziert die verfügbare Skill-Liste in die Sitzung</li><li><code>injectSyntheticContent()</code>: Verwendet Synthetic-Nachrichten zum Injizieren von Inhalten</li><li><code>getSessionContext()</code>: Ruft die Model- und Agent-Informationen der Sitzung ab</li></ul></details>`,85)])])}const p=n(r,[["render",l]]);export{c as __pageData,p as default};
